import React, { createContext, useContext, useState, useEffect } from "react";

export interface Product {
    id: number;
    name: string;
    category: string;
    stock: number;
    weight: number;
    price: number;
    threshold: number;
    description?: string;
}

interface ProductContextType {
    products: Product[];
    addProduct: (p: Omit<Product, "id" | "threshold">) => void;
    updateProductPrice: (id: number, newPrice: number) => void;
    deleteProduct: (id: number) => void;            // ← added
}

const ProductContext = createContext<ProductContextType | undefined>(undefined);

export const ProductsProvider: React.FC<{ children: React.ReactNode }> = ({
                                                                              children,
                                                                          }) => {
    const STORAGE_KEY = "inventory";
    const [products, setProducts] = useState<Product[]>(() => {
        const stored = localStorage.getItem(STORAGE_KEY);
        return stored ? JSON.parse(stored) : [];
    });

    // keep localStorage in sync
    useEffect(() => {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(products));
    }, [products]);

    const addProduct = (newProd: Omit<Product, "id" | "threshold">) => {
        const id = products.length ? Math.max(...products.map((p) => p.id)) + 1 : 1;
        setProducts((prev) => [
            ...prev,
            { ...newProd, id, threshold: newProd.stock },
        ]);
    };

    const updateProductPrice = (id: number, newPrice: number) => {
        setProducts((prev) =>
            prev.map((p) => (p.id === id ? { ...p, price: newPrice } : p))
        );
    };

    const deleteProduct = (id: number) => {
        setProducts((prev) => prev.filter((p) => p.id !== id));
    };

    return (
        <ProductContext.Provider
            value={{ products, addProduct, updateProductPrice, deleteProduct }}
        >
            {children}
        </ProductContext.Provider>
    );
};

export function useProducts() {
    const ctx = useContext(ProductContext);
    if (!ctx) throw new Error("useProducts must be inside a ProductsProvider");
    return ctx;
}
